let dimensionData = queries.downloadBackupFile.data.message;
const blob = new Blob([dimensionData], { type:  'text/csv;charset=utf-8;'});
const url = URL.createObjectURL(blob);
const link = document.createElement('a');
link.href = url;
link.download = page.variables.selectedBackupFileLocation.split("/")[3]; // Name of the file to be downloaded
document.body.appendChild(link);
link.click();
document.body.removeChild(link);
